import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface EnergyData {
  month: string;
  usage: number;
}

export enum AnalysisStatus {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR',
}

export interface AnalysisResult {
  data: EnergyData[];
  rawJson: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { EnergyData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Converts a File object to a Base64 string.
 */
const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const analyzeGraphImage = async (file: File): Promise<EnergyData[]> => {
  try {
    const imagePart = await fileToGenerativePart(file);

    const prompt = `
      Analyze the attached image of a bar graph. 
      Extract the 'Average daily usage' in kWh for each month listed on the X-axis.
      The Y-axis represents the usage in kWh.

      Return the data as a strictly valid JSON array of objects.
      Each object must have:
      - "month": The label for the month (e.g., "Apr 2022"). Combine month and year if available in the context.
      - "usage": The numerical value for that month. Estimate the value as accurately as possible based on the bar height.

      Example output format:
      [
        { "month": "Apr 2022", "usage": 15 },
        { "month": "May 2022", "usage": 28 }
      ]
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          imagePart,
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              month: { type: Type.STRING },
              usage: { type: Type.NUMBER }
            },
            required: ['month', 'usage']
          }
        }
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No data returned from Gemini.");
    }

    const data: EnergyData[] = JSON.parse(text);
    return data;

  } catch (error) {
    console.error("Error analyzing graph:", error);
    throw error;
  }
};

import React, { useRef, useState } from 'react';

interface ImageUploaderProps {
  onImageSelected: (file: File) => void;
  selectedImage: string | null;
  disabled: boolean;
}

const ImageUploader: React.FC<ImageUploaderProps> = ({ onImageSelected, selectedImage, disabled }) => {
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(false);
    if (disabled) return;

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const file = e.dataTransfer.files[0];
      if (file.type.startsWith('image/')) {
        onImageSelected(file);
      }
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onImageSelected(e.target.files[0]);
    }
  };

  const handleClick = () => {
    if (!disabled && fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  return (
    <div className="w-full">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        className="hidden"
        accept="image/*"
      />

      <div
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        onClick={handleClick}
        className={`
          relative border-2 border-dashed rounded-xl p-8 flex flex-col items-center justify-center text-center transition-all cursor-pointer h-80
          ${isDragging ? 'border-orange-500 bg-orange-500/10' : 'border-slate-600 hover:border-slate-500 hover:bg-slate-800/50'}
          ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
          ${selectedImage ? 'bg-slate-900' : ''}
        `}
      >
        {selectedImage ? (
          <div className="relative w-full h-full flex items-center justify-center">
            <img 
              src={selectedImage} 
              alt="Uploaded Preview" 
              className="max-h-full max-w-full object-contain rounded shadow-lg" 
            />
            <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity rounded">
               <p className="text-white font-medium bg-black/60 px-4 py-2 rounded-full backdrop-blur-sm">Click to change image</p>
            </div>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="w-16 h-16 bg-slate-700/50 rounded-full flex items-center justify-center mx-auto text-orange-500">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-8 h-8">
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5m-13.5-9L12 3m0 0l4.5 4.5M12 3v13.5" />
              </svg>
            </div>
            <div>
              <p className="text-lg font-semibold text-slate-200">Upload an image</p>
              <p className="text-sm text-slate-400 mt-1">Drag and drop or click to browse</p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ImageUploader;

