export const analyzeGraphImage = async (file: File): Promise<AnalysisResponse> => {
  try {
    const imagePart = await fileToGenerativePart(file);

    const prompt = `
      You are a high-precision data extraction engine. Your task is to extract exact numerical values from the attached bar graph image (electricity bill).

      **Step 1: Calibration (Y-Axis)**
      - Identify the vertical Y-axis labels. 
      - Note the specific interval between grid lines (e.g., 100, 200, 300).
      - **Metadata**: Record the lowest number (yAxisMin) and the top-most number on the axis scale (yAxisMax).

      **Step 2: Measurement (Data Extraction)**
      - For each bar, visually project a horizontal line from the absolute top edge of the bar to the Y-axis.
      - **Interpolate precisely**. Do not round to the nearest whole number unless the bar aligns exactly with a line. 
      - Example: If a bar is slightly above the midpoint between 10 and 20, estimate 16 or 17, not 15 or 20.
      - Be careful with the scale. If the scale starts at a non-zero number, adjust calculations accordingly.
      - Read the X-axis labels for the month.

      **Output**:
      Return a JSON object containing the metadata and the data array.

      Structure:
      {
        "metadata": {
          "yAxisMin": <number>, 
          "yAxisMax": <number>
        },
        "data": [
          { "month": "Jan", "usage": 12.4 },
          ...
        ]
      }

      Return ONLY the raw JSON string. No markdown formatting.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          imagePart,
          { text: prompt }
        ]
      },
      config: {
        thinkingConfig: {
            thinkingBudget: 4096
        }
      }
    });

    let text = response.text;
    if (!text) {
      throw new Error("No data returned from Gemini.");
    }

    // Clean up markdown code blocks
    text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    const result: AnalysisResponse = JSON.parse(text);

    // Basic validation
    if (!result.data || !Array.isArray(result.data)) {
        throw new Error("Invalid data format received from AI");
    }
    if (!result.metadata) {
        // Fallback if metadata is missing
        const maxUsage = Math.max(...result.data.map(d => d.usage));
        result.metadata = { yAxisMin: 0, yAxisMax: Math.ceil(maxUsage * 1.1) };
    }

    return result;

  } catch (error) {
    console.error("Error analyzing graph:", error);
    throw error;
  }
};

