      Analyze the attached image of a bar graph from an electricity bill.

      **Task 1: Identify Axis Scales**
      - **Y-Axis (Vertical)**: Read the numbers on the left-hand axis exactly as they appear. 
        - Find the lowest number (usually 0).
        - Find the highest number at the very top of the axis scale (this is often higher than the tallest bar).
        - These numbers define the "min" and "max" of the chart's frame.
      - **X-Axis (Horizontal)**: Identify the month labels.

      **Task 2: Extract Data Points**
      - For each bar, estimate the usage value (kWh) based on the Y-axis scale.
      - Be precise. If a bar is halfway between 10 and 20, it is 15.

      **Output Format**:
      Return a strictly valid JSON object with two keys: "metadata" and "data".

      Structure:
      {
        "metadata": {
          "yAxisMin": <number>, // The lowest value on the Y-axis scale (e.g., 0)
          "yAxisMax": <number>  // The highest value labeled on the Y-axis scale (e.g., 120)
        },
        "data": [
          { "month": "Apr 2022", "usage": 15 },
          { "month": "May 2022", "usage": 28.5 }
        ]
      }

      IMPORTANT: 
      - Return ONLY the raw JSON string. 
      - Do not use markdown formatting.
      - Ensure the "yAxisMax" reflects the top of the axis labels, not just the highest bar value. This is crucial for reproducing the graph's visual proportions.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          imagePart,
          { text: prompt }
        ]
      }
    });

    let text = response.text;
    if (!text) {
      throw new Error("No data returned from Gemini.");
    }

    // Clean up markdown code blocks
    text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    const result: AnalysisResponse = JSON.parse(text);

    // Basic validation
    if (!result.data || !Array.isArray(result.data)) {
        throw new Error("Invalid data format received from AI");
    }
    if (!result.metadata) {
        // Fallback if metadata is missing
        const maxUsage = Math.max(...result.data.map(d => d.usage));
        result.metadata = { yAxisMin: 0, yAxisMax: Math.ceil(maxUsage * 1.1) };
    }

    return result;

  } catch (error) {
    console.error("Error analyzing graph:", error);
    throw error;
  }
};

export interface EnergyData {
  month: string;
  usage: number;
}

export interface GraphMetadata {
  yAxisMin: number;
  yAxisMax: number;
}

export interface AnalysisResponse {
  data: EnergyData[];
  metadata: GraphMetadata;
}

export interface CalculatedEnergyData extends EnergyData {
  adjustedDailyUsage: number; // usage - 1
  daysInMonth: number;
  monthlyTotal: number; // adjusted * days
}

export interface CalculationSummary {
  last12MonthsTotal: number;
  last12MonthsAverage: number;
}

export enum AnalysisStatus {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR',
}

export interface AnalysisResult {
  data: EnergyData[];
  rawJson: string;
}

import React, { useState } from 'react';
import ImageUploader from './components/ImageUploader';
import DataVisualizer from './components/DataVisualizer';
import LoadingState from './components/LoadingState';
import { analyzeGraphImage } from './services/geminiService';
import { AnalysisResponse, AnalysisStatus, CalculatedEnergyData, CalculationSummary } from './types';

const App: React.FC = () => {
  const [status, setStatus] = useState<AnalysisStatus>(AnalysisStatus.IDLE);
  const [result, setResult] = useState<AnalysisResponse | null>(null);

  // New state for calculated values
  const [calculatedData, setCalculatedData] = useState<CalculatedEnergyData[] | null>(null);
  const [summary, setSummary] = useState<CalculationSummary | null>(null);

  const [error, setError] = useState<string | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const getDaysInMonth = (monthStr: string): number => {
    const lower = monthStr.toLowerCase();

    // Check for leap year if year is present (e.g., "Feb 2024")
    if (lower.includes('feb')) {
        const yearMatch = monthStr.match(/\d{4}/);
        if (yearMatch) {
            const year = parseInt(yearMatch[0]);
            if ((year % 4 === 0 && year % 100 !== 0) || year % 400 === 0) return 29;
        }
        return 28;
    }

    if (lower.includes('jan') || lower.includes('mar') || lower.includes('may') || 
        lower.includes('jul') || lower.includes('aug') || lower.includes('oct') || 
        lower.includes('dec')) {
        return 31;
    }

    if (lower.includes('apr') || lower.includes('jun') || lower.includes('sep') || 
        lower.includes('nov')) {
        return 30;
    }

    return 30; // Default fallback
  };

  const handleImageSelected = async (file: File) => {
    // Create preview URL
    const imageUrl = URL.createObjectURL(file);
    setSelectedImage(imageUrl);

    // Reset states
    setResult(null);
    setCalculatedData(null);
    setSummary(null);
    setError(null);
    setStatus(AnalysisStatus.ANALYZING);

    try {
      const analysisResult = await analyzeGraphImage(file);
      setResult(analysisResult);

      // --- Post-Processing Logic ---
      // 1. Calculate Monthly Totals: (Daily Usage - 1) * Days in Month
      const processedData: CalculatedEnergyData[] = analysisResult.data.map(item => {
          // Subtract 1 from the bar count (as requested)
          // Ensure we don't go below zero if the bar is tiny
          const adjustedDailyUsage = Math.max(0, item.usage - 1); 
          const daysInMonth = getDaysInMonth(item.month);
          const monthlyTotal = adjustedDailyUsage * daysInMonth;

          return {
              ...item,
              adjustedDailyUsage,
              daysInMonth,
              monthlyTotal
          };
      });

      setCalculatedData(processedData);

      // 2. Calculate Last 12 Months Summary
      // Take the last 12 items (or fewer if dataset is small)
      const last12 = processedData.slice(-12);
      const totalUsage = last12.reduce((sum, item) => sum + item.monthlyTotal, 0);
      const averageUsage = last12.length > 0 ? totalUsage / last12.length : 0;

      setSummary({
          last12MonthsTotal: totalUsage,
          last12MonthsAverage: averageUsage
      });

      setStatus(AnalysisStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to analyze image");
      setStatus(AnalysisStatus.ERROR);
    }
  };

  const handleReset = () => {
    setStatus(AnalysisStatus.IDLE);
    setResult(null);
    setCalculatedData(null);
    setSummary(null);
    setError(null);
    setSelectedImage(null);
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col">
      {/* Header */}
      <header className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-10">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="w-8 h-8 bg-gradient-to-tr from-orange-500 to-amber-500 rounded-lg flex items-center justify-center shadow-lg shadow-orange-500/20">
                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5 text-white">
                        <path fillRule="evenodd" d="M3 6a3 3 0 013-3h12a3 3 0 013 3v12a3 3 0 01-3 3H6a3 3 0 01-3-3V6zm4.5 7.5a.75.75 0 01.75.75v4.5a.75.75 0 01-1.5 0v-4.5a.75.75 0 01.75-.75zm3.75-3a.75.75 0 01.75.75v7.5a.75.75 0 01-1.5 0v-7.5a.75.75 0 01.75-.75zm3.75 5.25a.75.75 0 01.75.75v2.25a.75.75 0 01-1.5 0v-2.25a.75.75 0 01.75-.75z" clipRule="evenodd" />
                    </svg>
                </div>
                <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-100 to-slate-400">
                    GraphReader AI
                </h1>
            </div>
            {status === AnalysisStatus.SUCCESS && (
                <button 
                    onClick={handleReset}
                    className="text-sm px-4 py-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-300 transition-colors border border-slate-700"
                >
                    Analyze New Image
                </button>
            )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow container mx-auto px-4 py-8">
        <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">

            {/* Left Column: Input */}
            <div className="space-y-6">
                <div className="bg-slate-800/50 p-1 rounded-2xl border border-slate-700 shadow-xl">
                    <div className="bg-slate-900 rounded-xl p-6">
                        <h2 className="text-lg font-semibold mb-4 text-slate-200">Input Image</h2>
                        <ImageUploader 
                            onImageSelected={handleImageSelected} 
                            selectedImage={selectedImage}
                            disabled={status === AnalysisStatus.ANALYZING}
                        />
                        <div className="mt-4 text-sm text-slate-500">
                            <p className="flex items-center gap-2">
                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4 text-slate-600">
                                    <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                                </svg>
                                Supported formats: JPG, PNG. Optimized for bar charts.
                            </p>
                        </div>
                    </div>
                </div>

                {status === AnalysisStatus.ERROR && (
                    <div className="bg-red-500/10 border border-red-500/50 rounded-xl p-4 flex items-start gap-3">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5 text-red-500 mt-0.5">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008H12v-.008z" />
                        </svg>
                        <div>
                            <h3 className="text-red-500 font-medium text-sm">Analysis Failed</h3>
                            <p className="text-red-400/80 text-xs mt-1">{error}</p>
                        </div>
                    </div>
                )}
            </div>

            {/* Right Column: Results */}
            <div className="h-full min-h-[500px]">
                {status === AnalysisStatus.IDLE && (
                    <div className="h-full flex flex-col items-center justify-center text-center p-12 border-2 border-dashed border-slate-800 rounded-2xl bg-slate-800/20">
                        <div className="w-16 h-16 bg-slate-800 rounded-2xl flex items-center justify-center mb-4 text-slate-600 transform rotate-3">
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-8 h-8">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 3v11.25A2.25 2.25 0 006 16.5h2.25M3.75 3h-1.5m1.5 0h16.5m0 0h1.5m-1.5 0v11.25A2.25 2.25 0 0118 16.5h-2.25m-7.5 0h7.5m-7.5 0l-1 3m8.5-3l1 3m0 0l.5 1.5m-.5-1.5h-9.5m0 0l-.5 1.5m.75-9l3-3 2.148 2.148A12.061 12.061 0 0116.5 7.605" />
                            </svg>
                        </div>
                        <h3 className="text-lg font-medium text-slate-300">Ready to Analyze</h3>
                        <p className="text-slate-500 mt-2 max-w-sm">
                            Upload an image containing a bar graph to extract raw data and convert it into a digital format.
                        </p>
                    </div>
                )}

                {status === AnalysisStatus.ANALYZING && (
                    <div className="h-full flex items-center justify-center bg-slate-800/30 rounded-2xl border border-slate-800">
                         <LoadingState />
                    </div>
                )}

                {status === AnalysisStatus.SUCCESS && result && calculatedData && (
                    <DataVisualizer 
                        data={calculatedData} 
                        metadata={result.metadata} 
                        summary={summary}
                    />
                )}
            </div>

        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { CalculatedEnergyData, CalculationSummary, GraphMetadata } from '../types';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Cell,
  LabelList
} from 'recharts';

interface DataVisualizerProps {
  data: CalculatedEnergyData[];
  metadata?: GraphMetadata;
  summary: CalculationSummary | null;
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload as CalculatedEnergyData;
    return (
      <div className="bg-slate-900 border border-slate-700 p-4 rounded-lg shadow-xl">
        <p className="text-slate-200 font-semibold mb-2 border-b border-slate-700 pb-2">{label}</p>
        <div className="space-y-1 text-sm">
          <p className="text-slate-400 flex justify-between gap-4">
            <span>Raw Daily Avg:</span>
            <span className="text-slate-200 font-mono">{data.usage} kWh</span>
          </p>
          <p className="text-slate-400 flex justify-between gap-4">
            <span>Final Bar Count (-1):</span>
            <span className="text-orange-400 font-mono">{data.adjustedDailyUsage.toFixed(2)} kWh</span>
          </p>
          <p className="text-slate-400 flex justify-between gap-4">
            <span>Days in Month:</span>
            <span className="text-slate-200 font-mono">{data.daysInMonth}</span>
          </p>
          <div className="mt-2 pt-2 border-t border-slate-700">
             <p className="text-white font-bold flex justify-between gap-4">
                <span>Monthly Total:</span>
                <span className="text-green-400">{data.monthlyTotal.toFixed(1)} kWh</span>
             </p>
          </div>
        </div>
      </div>
    );
  }
  return null;
};

const DataVisualizer: React.FC<DataVisualizerProps> = ({ data, metadata, summary }) => {
  const [activeTab, setActiveTab] = useState<'chart' | 'json'>('chart');

  // We are now plotting Monthly Totals, not daily usage, so the domain metadata 
  // from the graph (which is daily) might be too small. Let's rely on auto for now 
  // or calculate max from our new data.
  // const yAxisDomain = [0, 'auto']; 

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 overflow-hidden shadow-xl h-full flex flex-col">

      {/* Summary Cards */}
      {summary && (
          <div className="grid grid-cols-2 gap-4 p-6 pb-2">
            <div className="bg-slate-700/50 p-4 rounded-lg border border-slate-600">
                <p className="text-slate-400 text-xs uppercase tracking-wider font-semibold">Last 12 Mo. Total</p>
                <p className="text-2xl font-bold text-white mt-1">
                    {summary.last12MonthsTotal.toFixed(0)} <span className="text-sm font-normal text-slate-400">kWh</span>
                </p>
            </div>
            <div className="bg-slate-700/50 p-4 rounded-lg border border-slate-600">
                <p className="text-slate-400 text-xs uppercase tracking-wider font-semibold">Last 12 Mo. Average</p>
                <p className="text-2xl font-bold text-white mt-1">
                    {summary.last12MonthsAverage.toFixed(0)} <span className="text-sm font-normal text-slate-400">kWh/mo</span>
                </p>
            </div>
          </div>
      )}

      <div className="flex border-b border-slate-700 mt-4">
        <button
          onClick={() => setActiveTab('chart')}
          className={`flex-1 py-3 text-sm font-medium transition-colors ${
            activeTab === 'chart'
              ? 'bg-slate-700/50 text-orange-400 border-b-2 border-orange-400'
              : 'text-slate-400 hover:text-slate-200 hover:bg-slate-700/30'
          }`}
        >
          Chart Visualization
        </button>
        <button
          onClick={() => setActiveTab('json')}
          className={`flex-1 py-3 text-sm font-medium transition-colors ${
            activeTab === 'json'
              ? 'bg-slate-700/50 text-blue-400 border-b-2 border-blue-400'
              : 'text-slate-400 hover:text-slate-200 hover:bg-slate-700/30'
          }`}
        >
          Calculated Data (JSON)
        </button>
      </div>

      <div className="p-6 flex-grow overflow-auto min-h-[400px]">
        {activeTab === 'chart' ? (
          <div className="h-full min-h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                data={data}
                margin={{
                  top: 30,
                  right: 30,
                  left: 20,
                  bottom: 60,
                }}
              >
                <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                <XAxis 
                  dataKey="month" 
                  stroke="#94a3b8" 
                  tick={{ fill: '#94a3b8', fontSize: 12 }}
                  tickLine={false}
                  axisLine={{ stroke: '#475569' }}
                  angle={-45}
                  textAnchor="end"
                  height={60}
                />
                <YAxis 
                  stroke="#94a3b8" 
                  tick={{ fill: '#94a3b8', fontSize: 12 }}
                  tickLine={false}
                  axisLine={false}
                  label={{ value: 'Total kWh', angle: -90, position: 'insideLeft', fill: '#64748b' }}
                />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: '#1e293b' }} />
                <Bar dataKey="monthlyTotal" radius={[4, 4, 0, 0]}>
                  <LabelList 
                    dataKey="monthlyTotal" 
                    position="top" 
                    fill="#cbd5e1" 
                    fontSize={11}
                    formatter={(val: number) => val.toFixed(0)}
                  />
                  {data.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill="#f97316" />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        ) : (
          <div className="h-full w-full bg-slate-900 rounded-lg p-4 overflow-auto border border-slate-700 flex flex-col">
             <div className="mb-4 text-xs text-slate-500 border-b border-slate-800 pb-2">
                 <span className="font-semibold text-slate-400">Calculation Formula:</span> 
                 (DailyUsage - 1) * DaysInMonth = MonthlyTotal
             </div>
            <pre className="text-sm text-green-400 font-mono whitespace-pre-wrap">
              {JSON.stringify({ summary, data }, null, 2)}
            </pre>
          </div>
        )}
      </div>

      {activeTab === 'chart' && (
        <div className="px-6 pb-4 pt-2">
            <p className="text-xs text-slate-500 text-center">
                Visualizing calculated monthly totals (adjusted). Hover bars for details.
            </p>
        </div>
      )}
    </div>
  );
};

export default DataVisualizer;

