import React, { useState } from 'react';
import ImageUploader from './components/ImageUploader';
import DataVisualizer from './components/DataVisualizer';
import LoadingState from './components/LoadingState';
import { analyzeGraphImage } from './services/geminiService';
import { AnalysisResponse, AnalysisStatus, CalculatedEnergyData, CalculationSummary } from './types';

const App: React.FC = () => {
  const [status, setStatus] = useState<AnalysisStatus>(AnalysisStatus.IDLE);
  const [result, setResult] = useState<AnalysisResponse | null>(null);

  // New state for calculated values
  const [calculatedData, setCalculatedData] = useState<CalculatedEnergyData[] | null>(null);
  const [summary, setSummary] = useState<CalculationSummary | null>(null);

  const [error, setError] = useState<string | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const getDaysInMonth = (monthStr: string): number => {
    const lower = monthStr.toLowerCase();

    // Check for leap year if year is present (e.g., "Feb 2024")
    if (lower.includes('feb')) {
        const yearMatch = monthStr.match(/\d{4}/);
        if (yearMatch) {
            const year = parseInt(yearMatch[0]);
            if ((year % 4 === 0 && year % 100 !== 0) || year % 400 === 0) return 29;
        }
        return 28;
    }

    if (lower.includes('jan') || lower.includes('mar') || lower.includes('may') || 
        lower.includes('jul') || lower.includes('aug') || lower.includes('oct') || 
        lower.includes('dec')) {
        return 31;
    }

    if (lower.includes('apr') || lower.includes('jun') || lower.includes('sep') || 
        lower.includes('nov')) {
        return 30;
    }

    return 30; // Default fallback
  };

  const handleImageSelected = async (file: File) => {
    // Create preview URL
    const imageUrl = URL.createObjectURL(file);
    setSelectedImage(imageUrl);

    // Reset states
    setResult(null);
    setCalculatedData(null);
    setSummary(null);
    setError(null);
    setStatus(AnalysisStatus.ANALYZING);

    try {
      const analysisResult = await analyzeGraphImage(file);
      setResult(analysisResult);

      // --- Post-Processing Logic ---
      // 1. Calculate Monthly Totals: (Daily Usage - 1) * Days in Month
      const processedData: CalculatedEnergyData[] = analysisResult.data.map(item => {
          // Subtract 1 from the bar count (as requested)
          // Ensure we don't go below zero if the bar is tiny
          const adjustedDailyUsage = Math.max(0, item.usage - 1); 
          const daysInMonth = getDaysInMonth(item.month);
          const monthlyTotal = adjustedDailyUsage * daysInMonth;

          return {
              ...item,
              adjustedDailyUsage,
              daysInMonth,
              monthlyTotal
          };
      });

      setCalculatedData(processedData);

      // 2. Calculate Last 12 Months Summary
      // Take the last 12 items (or fewer if dataset is small)
      const last12 = processedData.slice(-12);
      const totalUsage = last12.reduce((sum, item) => sum + item.monthlyTotal, 0);
      const averageUsage = last12.length > 0 ? totalUsage / last12.length : 0;

      setSummary({
          last12MonthsTotal: totalUsage,
          last12MonthsAverage: averageUsage
      });

      setStatus(AnalysisStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to analyze image");
      setStatus(AnalysisStatus.ERROR);
    }
  };

  const handleReset = () => {
    setStatus(AnalysisStatus.IDLE);
    setResult(null);
    setCalculatedData(null);
    setSummary(null);
    setError(null);
    setSelectedImage(null);
  };

  return (
    <div className="min-h-screen bg-black text-zinc-100 flex flex-col">
      {/* Header */}
      <header className="border-b border-zinc-900 bg-black/95 backdrop-blur-md sticky top-0 z-50">
