                    <svg viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-full h-full">
                       <path d="M5 5 L35 95 L55 35 L40 5 Z" fill="#4ade80" />
                       <path d="M60 35 L80 95 L95 5 L80 5 L65 50 Z" fill="#15803d" />
                       <circle cx="50" cy="45" r="15" fill="#dcfce7" fillOpacity="0.9" />
                       <path d="M42 38 C42 33.5817 45.5817 30 50 30 C54.4183 30 58 33.5817 58 38 C58 41.5 56 43.5 54 45.5 L54 50 H46 L46 45.5 C44 43.5 42 41.5 42 38 Z" fill="#dcfce7" stroke="#14532d" strokeWidth="2"/>
                       <rect x="46" y="51" width="8" height="6" fill="#166534" />
                    </svg>
                </div>
                <h1 className="text-xl font-bold text-white tracking-tight hidden xs:block">
                    WattWalker
                </h1>
            </div>

            <div className="flex items-center gap-2">
                {status === AnalysisStatus.SUCCESS && (
                    <button 
                        onClick={handleReset}
                        className="text-xs sm:text-sm px-3 py-2 rounded-lg bg-zinc-900 hover:bg-zinc-800 text-green-400 border border-zinc-800 transition-colors"
                    >
                        New Scan
                    </button>
                )}
            </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow container mx-auto px-4 py-6 sm:py-8">
        <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-6 lg:gap-8 items-start">

            {/* Left Column: Input */}
            <div className="space-y-6">
                <div className="bg-zinc-900/50 p-1 rounded-2xl border border-zinc-800 shadow-xl">
