import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Converts a File object to a Base64 string.
 */
const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const analyzeGraphImage = async (file: File): Promise<AnalysisResponse> => {
  try {
    const imagePart = await fileToGenerativePart(file);

    const prompt = `
      Analyze the attached image of a bar graph from an electricity bill.

      **Task 1: Identify Axis Scales (CRITICAL)**
      - **Y-Axis Labels**: List EVERY number label explicitly written on the Y-axis (the vertical axis). 
        - Example: If the axis shows 0, 10, 20, 30, 40, return exactly [0, 10, 20, 30, 40].
        - Do not calculate a new scale. Read what is there.
        - "yAxisMin" should be the lowest number found.
        - "yAxisMax" should be the highest number found on the axis labels.

      - **X-Axis (Horizontal)**: Identify the month labels.

      **Task 2: Extract Data Points**
      - For each bar, estimate the usage value (kWh) based on the Y-axis scale.
      - Be precise. If a bar is halfway between 10 and 20, it is 15.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          imagePart,
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            metadata: {
              type: Type.OBJECT,
              properties: {
                yAxisMin: { type: Type.NUMBER },
                yAxisMax: { type: Type.NUMBER },
                yAxisLabels: { 
                  type: Type.ARRAY, 
                  items: { type: Type.NUMBER } 
                }
              },
              required: ['yAxisMin', 'yAxisMax', 'yAxisLabels']
            },
            data: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  month: { type: Type.STRING },
                  usage: { type: Type.NUMBER }
                },
                required: ['month', 'usage']
              }
            }
          },
          required: ['metadata', 'data']
        }
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No data returned from Gemini.");
    }

    // With responseSchema, the text is guaranteed to be JSON
    const result: AnalysisResponse = JSON.parse(text);

    // Basic validation
    if (!result.data || !Array.isArray(result.data)) {
        throw new Error("Invalid data format received from AI");
    }

    return result;

  } catch (error) {
    console.error("Error analyzing graph:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import ImageUploader from './components/ImageUploader';
import DataVisualizer from './components/DataVisualizer';
import LoadingState from './components/LoadingState';
import { analyzeGraphImage } from './services/geminiService';
import { AnalysisResponse, AnalysisStatus, CalculatedEnergyData, CalculationSummary } from './types';

const App: React.FC = () => {
  const [status, setStatus] = useState<AnalysisStatus>(AnalysisStatus.IDLE);
  const [result, setResult] = useState<AnalysisResponse | null>(null);

  // State for calculated values
  const [calculatedData, setCalculatedData] = useState<CalculatedEnergyData[] | null>(null);
  const [summary, setSummary] = useState<CalculationSummary | null>(null);

  const [error, setError] = useState<string | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const getDaysInMonth = (monthStr: string): number => {
    const lower = monthStr.toLowerCase();

    // Check for leap year if year is present (e.g., "Feb 2024")
    if (lower.includes('feb')) {
        const yearMatch = monthStr.match(/\d{4}/);
        if (yearMatch) {
            const year = parseInt(yearMatch[0]);
            if ((year % 4 === 0 && year % 100 !== 0) || year % 400 === 0) return 29;
        }
        return 28;
    }

    if (lower.includes('jan') || lower.includes('mar') || lower.includes('may') || 
        lower.includes('jul') || lower.includes('aug') || lower.includes('oct') || 
        lower.includes('dec')) {
        return 31;
    }

    if (lower.includes('apr') || lower.includes('jun') || lower.includes('sep') || 
        lower.includes('nov')) {
        return 30;
    }

    return 30; // Default fallback
  };

  const handleImageSelected = async (file: File) => {
    // Create preview URL
    const imageUrl = URL.createObjectURL(file);
    setSelectedImage(imageUrl);

    // Reset states
    setResult(null);
    setCalculatedData(null);
    setSummary(null);
    setError(null);
    setStatus(AnalysisStatus.ANALYZING);

    try {
      const analysisResult = await analyzeGraphImage(file);
      setResult(analysisResult);

      // --- Post-Processing Logic ---
      const processedData: CalculatedEnergyData[] = analysisResult.data.map(item => {
          // Rule: Extract daily total as whole number, then subtract 1.
          // We round the raw usage first to get the "whole number" from the graph reading
          const roundedUsage = Math.round(item.usage);

          // Then subtract 1, ensuring we don't go below 0
          const adjustedDailyUsage = Math.max(0, roundedUsage - 1);

          const daysInMonth = getDaysInMonth(item.month);
          const monthlyTotal = adjustedDailyUsage * daysInMonth;

          return {
              ...item,
              adjustedDailyUsage,
              daysInMonth,
              monthlyTotal
          };
      });

      setCalculatedData(processedData);

      // Calculate Last 12 Months Summary (using the adjusted values)
      const last12 = processedData.slice(-12);
      const totalUsage = last12.reduce((sum, item) => sum + item.monthlyTotal, 0);
      const averageUsage = last12.length > 0 ? totalUsage / last12.length : 0;

      setSummary({
          last12MonthsTotal: totalUsage,
          last12MonthsAverage: averageUsage
      });

      setStatus(AnalysisStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to analyze image");
      setStatus(AnalysisStatus.ERROR);
    }
  };

  const handleReset = () => {
    setStatus(AnalysisStatus.IDLE);
    setResult(null);
    setCalculatedData(null);
    setSummary(null);
    setError(null);
    setSelectedImage(null);
  };

  return (
    <div className="min-h-screen bg-black text-zinc-100 flex flex-col">
      {/* Header */}
      <header className="border-b border-zinc-900 bg-black/95 backdrop-blur-md sticky top-0 z-50">
