const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload as CalculatedEnergyData;
    return (
      <div className="bg-zinc-900 border border-zinc-800 p-3 rounded-lg shadow-xl text-xs sm:text-sm">
        <p className="text-white font-semibold mb-2 border-b border-zinc-800 pb-2">{label}</p>
        <div className="space-y-1">
          <p className="text-white flex justify-between gap-4">
            <span>Daily Usage (Adj):</span>
            <span className="font-mono text-green-400">{data.adjustedDailyUsage} kWh</span>
          </p>
           <p className="text-zinc-500 flex justify-between gap-4 text-[10px]">
            <span>(Raw Reading: {Math.round(data.usage)})</span>
          </p>
          <p className="text-zinc-500 flex justify-between gap-4">
            <span>Days in Month:</span>
            <span className="font-mono">{data.daysInMonth}</span>
          </p>
          <div className="mt-2 pt-2 border-t border-zinc-800">
             <p className="text-green-400 font-bold flex justify-between gap-4">
                <span>Monthly Total:</span>
                <span>{data.monthlyTotal.toFixed(0)} kWh</span>
             </p>
          </div>
        </div>
      </div>
    );
  }
  return null;
};

// Helper function to get month index for sorting (0 = Jan, 11 = Dec)
const getMonthIndex = (monthStr: string): number => {
    const lower = monthStr.toLowerCase().trim();
    if (lower.startsWith('ja')) return 0;
    if (lower.startsWith('f')) return 1;
    if (lower.startsWith('mar')) return 2;
    if (lower.startsWith('ap')) return 3;
    if (lower.startsWith('may')) return 4;
    if (lower.startsWith('jun')) return 5;
    if (lower.startsWith('jul')) return 6;
    if (lower.startsWith('au')) return 7;
    if (lower.startsWith('s')) return 8;
    if (lower.startsWith('o')) return 9;
    if (lower.startsWith('n')) return 10;
    if (lower.startsWith('d')) return 11;
    return -1; // Fallback
};

// Helper to format month name (e.g. "Apr 2022" -> "April")
const formatMonthName = (monthStr: string): string => {
    const months = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
    const idx = getMonthIndex(monthStr);
    if (idx !== -1) return months[idx];
    return monthStr.split(' ')[0]; // Fallback to first word
};

const DataVisualizer: React.FC<DataVisualizerProps> = ({ data, metadata, summary }) => {
  // Default to table view since the prompt asks for a "Chart" matching the table image
  const [activeTab, setActiveTab] = useState<'chart' | 'table'>('table');

  // Determine domain from metadata
  const yAxisDomain: [number, number | string] = [
    metadata?.yAxisMin ?? 0,
    metadata?.yAxisMax ?? 'auto'
  ];

  const yAxisTicks = metadata?.yAxisLabels && metadata.yAxisLabels.length > 0 
    ? metadata.yAxisLabels 
    : undefined;

  // Process data for the Table View: Last 12 months, Sorted by Month Index
  const tableData = useMemo(() => {
    // 1. Get last 12 months from the timeline
    const last12 = [...data].slice(-12);

    // 2. Sort by Month (Jan -> Dec)
    return last12.sort((a, b) => getMonthIndex(a.month) - getMonthIndex(b.month));
  }, [data]);

  return (
    <div className="bg-zinc-900/50 rounded-xl border border-zinc-800 overflow-hidden shadow-xl h-full flex flex-col">

      {/* Summary Cards */}
      {summary && (
          <div className="grid grid-cols-2 gap-3 p-4 sm:p-6 pb-2">
            <div className="bg-zinc-900 p-4 rounded-lg border border-zinc-800">
                <p className="text-zinc-500 text-[10px] sm:text-xs uppercase tracking-wider font-semibold">Last 12 Mo. Total</p>
                <p className="text-xl sm:text-2xl font-bold text-white mt-1">
                    {summary.last12MonthsTotal.toFixed(0)} <span className="text-sm font-normal text-zinc-500">kWh</span>
                </p>
            </div>
            <div className="bg-zinc-900 p-4 rounded-lg border border-zinc-800">
                <p className="text-zinc-500 text-[10px] sm:text-xs uppercase tracking-wider font-semibold">Last 12 Mo. Average</p>
                <p className="text-xl sm:text-2xl font-bold text-white mt-1">
                    {summary.last12MonthsAverage.toFixed(0)} <span className="text-sm font-normal text-zinc-500">kWh/mo</span>
                </p>
            </div>
          </div>
      )}

      <div className="flex border-b border-zinc-800 mt-2">
         <button
          onClick={() => setActiveTab('table')}
          className={`flex-1 py-3 text-xs sm:text-sm font-medium transition-colors ${
            activeTab === 'table'
              ? 'bg-zinc-800/50 text-green-400 border-b-2 border-green-500'
              : 'text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800/30'
          }`}
        >
          Data Chart
        </button>
        <button
          onClick={() => setActiveTab('chart')}
          className={`flex-1 py-3 text-xs sm:text-sm font-medium transition-colors ${
            activeTab === 'chart'
              ? 'bg-zinc-800/50 text-green-400 border-b-2 border-green-500'
              : 'text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800/30'
          }`}
        >
          Visual Graph
        </button>
      </div>

      <div className="p-4 sm:p-6 flex-grow overflow-auto">
        {activeTab === 'chart' ? (
          <div className="h-[300px] sm:h-[400px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                data={data}
                margin={{
                  top: 20,
                  right: 10,
                  left: 0,
                  bottom: 60,
                }}
              >
                <CartesianGrid strokeDasharray="3 3" stroke="#27272a" vertical={false} />
                <XAxis 
                  dataKey="month" 
                  stroke="#52525b" 
                  tick={{ fill: '#71717a', fontSize: 11 }}
                  tickLine={false}
                  axisLine={{ stroke: '#3f3f46' }}
                  angle={-45}
                  textAnchor="end"
                  height={60}
                  interval={0}
                />
                <YAxis 
                  stroke="#a1a1aa" 
                  tick={{ fill: '#a1a1aa', fontSize: 11 }}
                  tickLine={false}
                  axisLine={false}
                  label={{ value: 'Avg Daily kWh', angle: -90, position: 'insideLeft', fill: '#a1a1aa', fontSize: 10 }}
                  domain={yAxisDomain}
                  ticks={yAxisTicks}
                  allowDecimals={false}
                />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: '#27272a' }} />
                {/* Visualizing Adjusted Usage to match the table */}
                <Bar dataKey="adjustedDailyUsage" radius={[4, 4, 0, 0]}>
                  <LabelList 
                    dataKey="adjustedDailyUsage" 
                    position="top" 
                    fill="#a1a1aa" 
                    fontSize={10}
                    formatter={(val: number) => val.toFixed(0)}
                  />
                  {data.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill="#22c55e" />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        ) : (
          <div className="h-full w-full overflow-auto">
             <table className="w-full text-sm text-left border-collapse border border-zinc-700">
                <thead className="text-xs text-black uppercase bg-white border-b-2 border-zinc-700">
                    <tr>
                        <th scope="col" className="px-4 py-3 border border-zinc-400 font-bold text-lg">MONTH</th>
                        <th scope="col" className="px-4 py-3 border border-zinc-400 font-bold text-center text-lg leading-tight">
                          DAILY<br/>USAGE
                        </th>
                        <th scope="col" className="px-4 py-3 border border-zinc-400 font-bold text-center text-lg leading-tight">
                          Monthly<br/>Usage
                        </th>
                    </tr>
                </thead>
                <tbody className="bg-white">
                    {tableData.map((row, index) => (
                        <tr key={index} className="border-b border-zinc-300">
                            <td className="px-4 py-2 border border-zinc-400 text-black text-lg">
                                {formatMonthName(row.month)}
                            </td>
                            <td className="px-4 py-2 border border-zinc-400 text-center text-black font-medium text-lg">
                                {row.adjustedDailyUsage}
                            </td>
                            <td className="px-4 py-2 border border-zinc-400 text-center font-medium text-black text-lg">
                                {row.monthlyTotal.toFixed(0)}
                            </td>
                        </tr>
                    ))}
                </tbody>
             </table>
             <div className="mt-4 text-xs text-zinc-500">
                 * Showing data for last 12 months, sorted by month.
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default DataVisualizer;
